// SPDX-License-Identifier: GPL-3.0
pragma solidity >=0.8.2 <0.9.0;

// Створюємо контракт StudentRegistry [cite: 3]
contract StudentRegistry {

    // 1. Створюємо структуру Student [cite: 4, 5]
    struct Student {
        string name; // [cite: 7]
        uint age;    // [cite: 8]
    }

    // 2. Створюємо динамічний масив студентів у storage [cite: 9]
    Student[] public students;

    // 3. Функція додавання нового студента [cite: 11]
    // Використовуємо calldata для _name, оскільки рядок лише читається і не змінюється (економить газ) [cite: 14, 77]
    function addStudent(string calldata _name, uint _age) public {
        students.push(Student(_name, _age));
    }

    // 3. Функція, яка повертає інформацію про студента за індексом [cite: 12]
    // Модифікатор view, бо функція тільки читає стан [cite: 79]
    // Повертає структуру за допомогою memory, оскільки створюється тимчасова копія для виведення [cite: 14, 78]
    function getStudent(uint _index) public view returns (Student memory) {
        return students[_index];
    }

    // 3. Функція повертає кількість студентів [cite: 13]
    // Модифікатор view, бо ми читаємо довжину масиву зі стану [cite: 79]
    function studentsCount() public view returns (uint) {
        return students.length;
    }
}

